def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Resolve option defaults that are specified as a mapping from
    another option's value to a default value, e.g.
    ``default={"--protocol": {"http": 80, "https": 443}}``.

    This runs after every parameter has consumed its command line
    argument, environment variable, and default map value, so the
    referenced options' final values are available. Only applies to
    options whose value source is still :attr:`ParameterSource.DEFAULT`.
    """
    params = self.get_params(ctx)
    opt_map: dict[str, Parameter] = {}

    for param in params:
        if isinstance(param, Option):
            for decl in (*param.opts, *param.secondary_opts):
                opt_map[decl] = param

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore
            continue

        resolved = None

        for source_decl, mapping in param.default.items():
            source_param = opt_map.get(source_decl)

            if source_param is None:
                continue

            source_value = ctx.params.get(source_param.name)  # type: ignore
            key = str(source_value)

            if key in mapping:
                resolved = mapping[key]

        if resolved is None:
            continue

        value = param.type_cast_value(ctx, resolved)

        if param.callback is not None:
            value = param.callback(ctx, param, value)

        if param.expose_value:
            ctx.params[param.name] = value  # type: ignore

